var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"전하께서 도착하셨다!","JPN":"殿下のご到着だ！","ENG":"His Royal Highness has arrived!","TWN":"全員，列隊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"전원, 도열!","JPN":"全員、整列！","ENG":"Troops, line up!","TWN":"迎接殿下！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"들어라, 제국의 신민들이여!","JPN":"聞け、帝国の臣民たちよ！","ENG":"Hear me, subjects of the Empire!","TWN":"帝國的百姓們，請聽我說！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_1"},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"오늘 그대들은 제국을 지키기 위해 여기 모인 것이 아니다!","JPN":"今日は帝国を守るためにここに集まったのではない！","ENG":"You are not gathered here today to protect the Empire!","TWN":"今天你們聚集於此，不是為了保衛帝國！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_2"},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"센트럴 팰리스에서 그대들의 생환을 기도하고 있을 아내와 남편, 그리고 아들딸들을 위해!","JPN":"セントラルパレスで各自の生還を祈っているであろう妻と夫、そして息子や娘のために！","ENG":"You are here to protect your beloved spouse and children!","TWN":"是為了在聖特羅貝里斯祈禱你們平安歸來的妻子、丈夫還有兒女們！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_3"},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"유린당한 여덟 대륙과 마지막으로 남은 이 땅을 되찾기 위해!","JPN":"蹂躙された八つの大陸と最後に残ったこの地を取り戻すために！","ENG":"To take back the eight lost continents and this very land that has been taken from us!","TWN":"為了收復被踐踏的八塊大陸和最後僅存的這片土地！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_4"},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나아가 저들이 속삭이는 멸망으로부터 우리의 내일을 지키기 위해!","JPN":"ひいては、奴らの思惑である滅亡から我々の未来を守るために！","ENG":"To protect the days of tomorrow, from the whispers of annihilation!","TWN":"為了在毀滅的私語中守護我們的未來！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_5"},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대들과 나는 여기 모인 것이다!","JPN":"我らはこうしてここに集まったのだ！","ENG":"That is why you and I are gathered here!","TWN":"我和你們才會聚集於此！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_6"},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저편에서 마왕의 군세가 다가오고 있다.","JPN":"あの向こうでは魔王の軍勢が押し寄せてきている。","ENG":"The forces of the Demon Lord approach us from far beyond.","TWN":"那邊，魔王的軍隊正在逼近。"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_7"},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"두려울 것이다. 어쩌면 도망치고 싶을지도 모르지.","JPN":"恐ろしいだろう、逃げたくなるだろう。","ENG":"Perhaps you are terrified. Perhaps you wish to run away.","TWN":"你們會害怕，說不定還會想要逃跑。"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_8"},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 우리 모두 그들에게 점령된 땅을 이 두 눈으로 똑똑히 목격하지 않았던가?","JPN":"だが、我々が全員が奴らに奪われた地がどうなったか、しかとその目で見てきたはずだ！","ENG":"However, you have witnessed the land they conquered with our own eyes.","TWN":"但是，我們親眼目睹了被他們佔領的土地是怎麼變成了廢墟！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_9"},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마왕은, 네헤모트는 점령자가 아니다!","JPN":"魔王は、ネヘモトは征服者ではない！","ENG":"Nehemoth, the Demon Lord, does not seek to conquer!","TWN":"魔王，貝赫莫特不是征服者！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_10"},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그는 우리에게 아무것도 원하지 않는다! 그저 이 세상에 아무것도 남기지 않으려 할 뿐!","JPN":"奴は、我々に何かを望んでいるわけではない！　ただこの世からすべてを消し去ろうとしているだけだ！","ENG":"He does not want anything from us! He merely seeks to destroy!","TWN":"他不想從我們身上得到任何東西！他只是想讓這個世界燒成一塊焦土！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_11"},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 두렵다면 저 계곡 너머에 펼쳐진 황폐한 땅을 떠올려라.","JPN":"だから、恐怖に負けそうになったら、あの渓谷の向こう側に広がっている荒廃した土地を思い出せ。","ENG":"Should you be afraid, envision the barren wasteland beyond the creek.","TWN":"所以，害怕的話，就想一想溪谷那頭的荒地。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_12"},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우리의 아내와 남편들에게.","JPN":"我々の妻と夫に。","ENG":"For it will be your only legacy if you choose to flee.","TWN":"那是能夠留給你們妻子、你們丈夫，"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_13"},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"훗날 새롭게 이 땅을 일굴 아들딸들에게.","JPN":"そして将来この地を開拓していく子孫たちに。","ENG":"To your wives and your husbands.","TWN":"還有日後要新開墾這片土地的兒女們的唯一的東西！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_14"},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"싸움에서 도망친다면 그대들이 남겨야 할 것이다!","JPN":"戦いから逃げれば、この状況を彼らに残すことになる！","ENG":"And to your children, who will be the ones to cultivate these lands!","TWN":"如果我們在戰鬥中逃跑，那留給他們的就只有溪谷那頭的荒地！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_15"},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇기에 우리의 목표는 무엇인가!","JPN":"だからこそ、我々の目標は何だ！","ENG":"What is it that we seek?","TWN":"回答我，我們的目標是什麼！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_16"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"승리! 승리!!","JPN":"勝利！　勝利！","ENG":"Victory! Victory!","TWN":"勝利！勝利！！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"네헤모트에게 죽음을! 승리의 영광을!","JPN":"ネヘモトに死を！　我々に勝利の栄光を！","ENG":"Death to Nehemoth! Glorious victory!","TWN":"殺死貝赫莫特！取得勝利的榮耀！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다! 승리다!","JPN":"そうだ！　勝利だ！","ENG":"Yes, victory!","TWN":"是的，是勝利！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_17"},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어떤 대가를 지불하더라도 반드시 그것을 손에 넣겠다!","JPN":"いかなる代償を払ってでも、必ず掴んでみせよう！","ENG":"Victory shall be claimed, whatever the cost may be!","TWN":"不管付出什麼代價，我們都要取得勝利！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_18"},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이것은 생존을 위한 투쟁이기에!","JPN":"これは生存への闘争だからだ！","ENG":"For this is a war of survival!","TWN":"因為這是決定生死存亡的鬥爭！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_19"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"와아아아아아아아!!","JPN":"うおおおおおおお！！","ENG":"*Loud Cheer*","TWN":"哇噢噢噢噢！！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"아르카데나 제국 만세! 황태자 전하 만세! 구원 기사단 만세!","JPN":"アルカデナ帝国万歳！　皇太子殿下万歳！　救世騎士団万歳！","ENG":"Long live Arcadena! Long live His Highness! Long live the Knights of Redemption!","TWN":"艾爾卡特納帝國萬歲！皇太子殿下萬歲！救贖騎士團萬歲！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자께서 오셨으니 우리의 구원은 예정되어 있도다!","JPN":"救世主様が来てくださった以上、我々は必ず救われる！","ENG":"Salvation is upon us, with the Savior in our favor!","TWN":"救贖者來了，所以我們的救贖也會如約而至！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"행정관들이 또 머리를 쥐어뜯겠군. 전날까지 작성한 연설문과는 완전히 달라졌어.","JPN":"行政官たちがまた頭を抱えるだろうな、これは。昨日まで用意していた演説とはまったく違う内容だ。","ENG":"The officials are going to have a hard time dealing with this. His speech is nothing like the one he wrote yesterday.","TWN":"行政官們又要生氣了。和前一天寫的講稿完全不一樣。"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"왜 그래, 레이 선배? 뭔가 마음에 걸리는 거라도 있어?","JPN":"どうしたの、レイ先輩？　何か気掛かりでもあるの？","ENG":"What's wrong, Ray? Is something bothering you?","TWN":"你怎麼了，雷伊前輩？有什麼放心不下的嗎？"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"으, 응. 아니야. 나는 그저…….","JPN":"う、うん、いや。僕はただ……","ENG":"O-oh. Nothing. I just...","TWN":"呃，嗯，沒有，我就是在想……"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……늑대가 말했어. 마왕을 막지 못하면 세계는 멸망한다고.","JPN":"……狼が言っていたんだ。魔王を止めることができなければ世界は滅ぶって。","ENG":"...I just got reminded of what the Wolf said. If we don't stop the Demon Lord, this world will perish.","TWN":"……狼說過，不能阻止魔王的話，世界就會滅亡。"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하지만 여기까지 오는 동안 이미 많은 사람들이 죽거나 다쳤어.","JPN":"でもここに至るまでにも、すでに多くの人が死んだり傷ついたりしている。","ENG":"But so many people have been hurt or killed on this journey.","TWN":"但是一路走到現在，已經有太多人犧牲或受傷了。"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저 사람들마저 희생되고……. 그런데도 실패한다면.","JPN":"あの人たちも犠牲になって……それでも失敗してしまったら。","ENG":"What if these people were also to be sacrificed... and we still fail?","TWN":"如果連那些人也犧牲了……結果卻還是失敗的話。"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"우린, 어떻게 해야 할까?","JPN":"僕たちはどうすればいいんだろう？","ENG":"What should we do?","TWN":"我們，該怎麼辦？"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"지금은 뒷일을 걱정할 때가 아니야, 레이.","JPN":"今は先の事を心配している場合じゃないぞ、レイ。","ENG":"Now is not the time to worry about the aftermath, Ray.","TWN":"現在不是擔心以後的時候，雷伊。"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"저 사람들은 전부 각오한 거다. 그럼에도 마왕에게 맞서 싸우겠다고.","JPN":"あの者たちは皆覚悟を決めているんだ。それをわかった上で魔王に立ち向かうと。","ENG":"These people are determined. They are willing to fight against the Demon Lord, even if it means losing their lives.","TWN":"那些人都做好心理準備了，即便如此也要對抗魔王。"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"두려워하지 마. 구원자인 네가 걱정하면 다른 병사들까지 전염될 거다.","JPN":"恐れるな。救世主である君が不安がっていると、他の兵士たちにまで広がってしまう。","ENG":"Don't be afraid. If the Savior shows fear, the rest of the soldiers will too.","TWN":"不要害怕，身為救贖者的你如果憂慮了，會讓其他士兵也感染上這種情緒的。"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……응. 알겠어, 알렌.","JPN":"……うん。わかった、アレン。","ENG":"...Understood, Allen.","TWN":"……嗯，我知道了，艾倫。"},"stage":{"bg":"CAMP","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마왕의 수하들이 우리를 막아설 것이다. 치열한 전투가 되겠지.","JPN":"魔王の手下共は我々に立ちはだかるだろう。激しい戦いになることは明白だ。","ENG":"The forces of the Demon Lord will stand in our way. There will be blood.","TWN":"魔王的手下會阻止我們。戰鬥會很激烈！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_20"},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"허나 두려워말라! 구원 기사단이 선봉에 설 테니!","JPN":"しかし恐れるな！　救世騎士団が先鋒に立って戦う！","ENG":"Fear not, however! As the Knights of Redemption will lead you!","TWN":"不過不要害怕！救贖騎士團會衝在最前方！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_21"},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"구원이 눈앞에 있다! 그리고 그것은 지금!","JPN":"救いは目の前だ！　そしてそれは今！","ENG":"Salvation awaits us! And it shall be delivered...","TWN":"救贖已離我們不遠！我已經看到了，救贖——"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_22"},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네헤모트의 목에 걸려 있다!","JPN":"ネヘモトの首にかかっている！","ENG":"When we cut off the head of the Demon Lord!","TWN":"就掛在貝赫莫特的首級之上！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_23"},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"전군! 출정이다!","JPN":"全軍！　出征！","ENG":"All forces! To battle!","TWN":"全軍！出征！"},"stage":{"bg":"MS_1108","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_24"}]`);export{e as default};